const now = Math.floor(Date.now() / 1000);
const desde = now - 30 * 60;

return [{
  json: {
    begin_at: desde,
    end_at: now,
    request_id: $execution.id + '-' + now
  }
}];

// task_status numérico (v2 API)
// 2 = success, 3 = failed/starting_failure, 4 = terminated, 5 = timeout
const EVENT_MAP = {
  2: 'ATERRIZAJE',
  3: 'FALLA_DESPEGUE',
  4: 'DESPEGUE_FALLIDO',
  5: 'DESPEGUE_FALLIDO'
};

const FALLA_STATUS = [3, 4, 5];

const esc = s => s ? String(s).replace(/'/g, "''") : null;
const str = s => (s !== null && s !== undefined && s !== '') ? `'${esc(s)}'` : 'NULL';
const bool = b => b ? 'true' : 'false';

const tasks = $json.data?.list || [];

if (!Array.isArray(tasks) || tasks.length === 0) return [];

return tasks
  .filter(t => EVENT_MAP[t.task_status] && t.completed_at)
  .map(t => ({
    json: {
      sql: `INSERT INTO vuelos_log
        (event_id, evento, nombre_dron, nombre_dock, site, piloto, detalle_vuelo, timestamp_flytbase, despegue_fallido)
      VALUES (
        ${str(t.flight_task_id || t.uuid)},
        ${str(EVENT_MAP[t.task_status])},
        ${str(t.drone_sn || t.sn)},
        ${str(t.take_off_airport_sn || t.sn)},
        'CAM',
        ${str(t.user_name)},
        ${str(t.task_name || t.name)},
        ${str(t.completed_at || t.run_at)}::timestamptz,
        ${bool(FALLA_STATUS.includes(t.task_status))}
      )
      ON CONFLICT (event_id) DO NOTHING`
    }
  }));
